sd-cwt-types = sd-cwt-issued / kbt-cwt / sd-cwt-preissued
sd-cwt-issued = #6.18([ protected: bstr .cbor sd-protected, sd-unprotected, payload: bstr .cbor sd-payload, signature: bstr ])
sd-protected = { &(typ: 16) ^ => 293 / "application/sd-cwt", &(alg: 1) ^ => int, ? &(kid: 4) ^ => bstr, ? &(CWT_Claims: 15) ^ => issued_sd_cwt_map, ? &(sd_alg: 170) ^ => int, ; -16 for sha-256 ? &(sd_aead: 172) ^ => uint .size 2, * label => safe_value }
sd-unprotected = { ? &(sd_claims: 17) ^ => salted-array, ? &(sd_aead_encrypted_claims: 171) ^ => aead-encrypted-array, * label => safe_value }
sd-payload = { ; standard claims &(iss: 1) ^ => tstr, ; "https://issuer.example" ? &(sub: 2) ^ => tstr, ; "https://device.example" ? &(aud: 3) ^ => tstr, ; "https://verifier.example/app" ? &(exp: 4) ^ => secs, ; 1883000000 ? &(nbf: 5) ^ => secs, ; 1683000000 ? &(iat: 6) ^ => secs, ; 1683000000 ? &(cti: 7) ^ => bstr, &(cnf: 8) ^ => safe_map, ; key confirmation ? &(vct: 11) ^ => bstr, ? &(cnonce: 39) ^ => bstr, ; ? redacted_claim_keys ^ => [ * bstr ], * label => issued_sd_cwt_value }
kbt-cwt = #6.18([ protected: bstr .cbor kbt-protected, kbt-unprotected, payload: bstr .cbor kbt-payload, signature: bstr ])
kbt-protected = { &(typ: 16) ^ => 294 / "application/kb+cwt", &(alg: 1) ^ => int, &(kcwt: 13) ^ => sd-cwt-issued, * label => safe_value }
kbt-unprotected = { * label => safe_value }
kbt-payload = { &(aud: 3) ^ => tstr, ; "https://verifier.example/app" time-or-cti-claims, ? &(cnonce: 39) ^ => bstr, * label => safe_value }
time-or-cti-claims = ( ; Requires either time claims that include an iat OR a cti claim. ; Note that in CDDL, the // operator has very low precedence (see ; Section 2.2.2 of RFC 8610) ; ; It is possible to have both a cti and time claims, but ; time-or-cti-claims insures at least cti or iat is present ? &(exp: 4) ^ => secs, ? &(nbf: 5) ^ => secs, &(iat: 6) ^ => secs // &(cti: 7) ^ => bstr ) sd-cwt-preissued = #6.18([ protected: bstr .cbor sd-protected, sd-unprotected, payload: bstr .cbor preissuance_map, signature: bstr ])
; CWT claim legal values only safe_map = { * label => safe_value }
safe_value = int / tstr / bstr / [ * safe_value ] / safe_map / #6.<safe_tag>(safe_value) / #7.<safe_simple> / float
; legal values in issued SD-CWT issued_sd_cwt_map = { ? redacted_claim_keys ^ => [ * bstr ], * label => issued_sd_cwt_value }
issued_array_element = redacted_claim_element / issued_sd_cwt_value
issued_sd_cwt_value = int / tstr / bstr / [ * issued_array_element ] / issued_sd_cwt_map / #6.<safe_tag>(issued_sd_cwt_value) / #7.<safe_simple> / float
; legal values in claim set sent to Issuer preissuance_label = label / #6.<TO_BE_REDACTED_TAGNUM>(label) / #6.<TO_BE_DECOY_TAGNUM>(uint .gt 0)
preissuance_map = { * preissuance_label => preissuance_value }
preissuance_value = int / tstr / bstr / [ * preissuance_value ] / preissuance_map / #6.<safe_tag>(preissuance_value) / #7.<safe_simple> / float
; CBOR tag number for wrapping to-be-redacted keys or elements TO_BE_REDACTED_TAGNUM = 58 ; CBOR tag number for indicating a decoy value is to be inserted here TO_BE_DECOY_TAGNUM = 62
label = int / tstr .size (1..255) safe_tag = uint .ne (TO_BE_REDACTED_TAGNUM / TO_BE_DECOY_TAGNUM / REDACTED_ELEMENT_TAGNUM)
; exclude reserved simple values (24 through 31) from Table 4 of ; RFC 8949, and redacted keys array safe_simple = 0..23 / 32..58 / 60..255 secs = int / float53 float53 = -9007199254740992.0..9007199254740992.0 ; from 2^53 to 2^53
salted-array = [ +bstr-encoded-salted ]
bstr-encoded-salted = bstr .cbor salted-entry salted-entry = salted-claim / salted-element / decoy salted-claim = [ bstr .size 16, ; 128-bit salt any, ; Claim Value (int / text) ; Claim Key ] salted-element = [ bstr .size 16, ; 128-bit salt any ; Claim Value ] decoy = [ bstr .size 16 ; 128-bit salt ]
aead-encrypted-array = [ +aead-encrypted ] aead-encrypted = [ bstr .size 16, ; 128-bit nonce bstr, ; the encryption ciphertext output of a ; bstr-encoded-salted bstr ; the corresponding authentication tag ]
; redacted_claim_keys is used as a map key. The corresponding value is ; an array of Blinded Claim Hashes whose corresponding unblinded map ; keys and values are in the same map. redacted_claim_keys = #7.59 ; CBOR simple value 59
; CBOR tag for wrapping a redacted element in an array REDACTED_ELEMENT_TAGNUM = 60
; redacted_claim_element is used in CDDL payloads that contain ; array elements that are meant to be redacted. redacted_claim_element = #6.<REDACTED_ELEMENT_TAGNUM>( bstr )
